#!/bin/bash
# HERCOSSNUX NPU - Fase A, Paso 9: reestructuracion de memorias para BRAM.
#
# PROBLEMA CORREGIDO: las memorias de pesos tenian lecturas SIMULTANEAS que
# impiden el mapeo a BRAM (maximo 2 puertos):
#     w2_ram (1152 B): 64 lecturas por ciclo  -> ahora 1
#     w_ram    (72 B):  8 lecturas por ciclo  -> ahora 1
# Medido con yosys sobre una replica del patron y solo 8 de las 64 lecturas:
# 20166 celdas frente a 5622 del molde de una lectura (factor 3.6x), con
# "Number of memories: 0" -> la memoria se disolvia en flip-flops.
#
# SOLUCION: precarga de pesos en registros.
#   conv1: los 72 pesos se cargan UNA vez por imagen
#   conv2: los 64 pesos del (tile,kstep) se cargan una vez, con los bucles
#          reordenados (kstep fuera, pixel dentro) y acumuladores externos
#          de 8 canales x 64 pixeles int32
#
# CRITERIO: las firmas congeladas NO cambian.
#   conv1  0xE4C64381
#   pool2  0xA87E298C   logits 0xF7FF3389   clase 0x6084FD2A
#
# ESTE PASO REEMPLAZA rtl/npu_seq_conv1.vhd y rtl/npu_seq_full.vhd.
# Requiere Pasos 1-3, 6, 7 y 8 ya instalados.
# Linea esperada al final:
# NPU PASO9 OK BRAM FIRMAS INVARIANTES
(
set -e
DIR="$HOME/vhdl_repo/IP_Cores/NPU"
for f in model/npu_weights.hex rtl/npu_array.vhd rtl/npu_top.vhd \
         tb/tb_npu_seq_conv1.vhd tb/tb_npu_seq_full.vhd tb/tb_npu_top.vhd; do
  if [ ! -f "$DIR/$f" ]; then
    echo "FALLO: falta $f (corre primero los Pasos 1-3, 6, 7 y 8)"; exit 1
  fi
done
# Respaldo de las versiones anteriores antes de reemplazarlas
mkdir -p "$DIR/rtl/prev_paso9"
cp "$DIR/rtl/npu_seq_conv1.vhd" "$DIR/rtl/prev_paso9/" 2>/dev/null || true
cp "$DIR/rtl/npu_seq_full.vhd"  "$DIR/rtl/prev_paso9/" 2>/dev/null || true
base64 -d << "EOF" > "$DIR/rtl/npu_seq_conv1.vhd"

EOF
base64 -d << "EOF" > "$DIR/rtl/npu_seq_full.vhd"

EOF
base64 -d << "EOF" > "$DIR/run_bram.sh"

EOF
base64 -d << "EOF" > "$DIR/run_bram_mut.sh"

EOF
chmod +x "$DIR/run_bram.sh" "$DIR/run_bram_mut.sh"
cd "$DIR"
bash run_bram.sh
)
